console.log('[EDUCATIONAL DEMO] Method 3: XMLHttpRequest exfiltration (simulated)');

// Method 4: Fetch API (simulated)
console.log('[EDUCATIONAL DEMO] Method 4: Fetch API exfiltration (simulated)');

